class Solution:
    def maximumCount(self, nums: List[int], queries: List[List[int]]) -> List[int]:
        def is_prime(x):
            if x < 2:
                return False
            for i in range(2, int(x**0.5) + 1):
                if x % i == 0:
                    return False
            return True

        res = []
        for idx, val in queries:
            nums[idx] = val
            prefix_sum = 0
            suffix_sum = 0
            prefix_distinct = 0
            suffix_distinct = 0
            for i in range(len(nums)):
                if i < idx:
                    if is_prime(nums[i]):
                        prefix_sum += 1
                        if nums[i] not in [x for x in nums[:i] if is_prime(x)]:
                            prefix_distinct += 1
                else:
                    if is_prime(nums[i]):
                        suffix_sum += 1
                        if nums[i] not in [x for x in nums[idx+1:] if is_prime(x)]:
                            suffix_distinct += 1
            res.append(prefix_distinct + suffix_distinct)
        return res
